                                    const nextSettings = {
                                        ...settings,
                                        ollama: {
                                            ...settings.ollama,
                                            numCtx: Number(event.target.value),
                                        },
                                    };
                                    void handleSave(nextSettings);
                                }}
                                className="h-10 w-full rounded-xl border-border/40 bg-background font-mono typo-caption"
                            />
                        </div>
                    </div>
                    <div className="flex flex-col gap-3 sm:flex-row sm:items-center">
                        <Button
                            variant="outline"
                            size="sm"
                            onClick={(e) => {
                                e.preventDefault();
                                e.stopPropagation();
                                void checkOllama();
                            }}
                            className={C_ACCOUNTSTAB_5}
                        >
                            <RefreshCw className={cn("h-3 w-3 mr-2", !isRunning && "animate-spin")} />
                            {t('accounts.check')}
                        </Button>
                        {!isRunning && (
