                                        isLoadingMore={isLoadingMore}
                                        hasMoreCommits={hasMoreCommits}
                                        handleCommitSelect={handleCommitSelect}
                                        handleLoadMoreCommits={handleLoadMoreCommits}
                                        fetchGitData={fetchGitData}
                                        t={t}
                                    />
                            )}
