                    </ScrollArea>
                </div>

                <div className="w-80 border-l border-border/40 bg-muted/5 p-6 space-y-10 overflow-y-auto hidden lg:block">
                    {gitData && (
                        <GitStatusHeader
                            gitData={gitData}
