            <div style={style}>
                <WorkspaceExplorerInlineRow
                    rowKey={row.key}
                    depth={row.depth}
                    draftName={row.draftName}
                    actionType={row.actionType}
                    placeholder={inlinePlaceholder}
                    isFocused={focusedRowKey === row.key}
